<!-- 功能说明
管理端数据可视化页面，展示小程序基础数据（访问人数、订单数、成交金额）和产品数据（浏览量、加购数、下单数），
支持按日 / 周 / 月筛选、数据导出，核心对接数据统计接口，使用 uCharts 实现图表展示。 -->
<template>
  <view class="stat-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">数据统计</text>
      <button class="export-btn" @click="exportData">导出数据</button>
    </view>
    
    <!-- 筛选条件 -->
    <view class="filter-container">
      <text class="filter-label">时间范围：</text>
      <picker 
        class="time-picker"
        :range="timeRangeList"
        :value="selectedTimeRange"
        @change="handleTimeRangeChange"
      >
        <view class="picker-content">
          <text>{{timeRangeList[selectedTimeRange]}}</text>
          <image src="../../static/images/icon-arrow-down.png" class="picker-icon"></image>
        </view>
      </picker>
    </view>
    
    <!-- 基础数据卡片 -->
    <view class="data-card-group">
      <view class="data-card">
        <text class="card-title">访问人数</text>
        <text class="card-value">{{baseStat.visitCount || 0}}人</text>
        <text class="card-desc" :class="baseStat.visitGrowth >= 0 ? 'growth-up' : 'growth-down'">
          {{baseStat.visitGrowth >= 0 ? '+' : ''}}{{baseStat.visitGrowth || 0}}%
        </text>
      </view>
      <view class="data-card">
        <text class="card-title">新增用户</text>
        <text class="card-value">{{baseStat.newUserCount || 0}}人</text>
        <text class="card-desc" :class="baseStat.newUserGrowth >= 0 ? 'growth-up' : 'growth-down'">
          {{baseStat.newUserGrowth >= 0 ? '+' : ''}}{{baseStat.newUserGrowth || 0}}%
        </text>
      </view>
      <view class="data-card">
        <text class="card-title">订单总数</text>
        <text class="card-value">{{baseStat.orderCount || 0}}单</text>
        <text class="card-desc" :class="baseStat.orderGrowth >= 0 ? 'growth-up' : 'growth-down'">
          {{baseStat.orderGrowth >= 0 ? '+' : ''}}{{baseStat.orderGrowth || 0}}%
        </text>
      </view>
      <view class="data-card">
        <text class="card-title">成交金额</text>
        <text class="card-value">¥{{(baseStat.transactionAmount || 0).toFixed(2)}}</text>
        <text class="card-desc" :class="baseStat.amountGrowth >= 0 ? 'growth-up' : 'growth-down'">
          {{baseStat.amountGrowth >= 0 ? '+' : ''}}{{baseStat.amountGrowth || 0}}%
        </text>
      </view>
    </view>
    
    <!-- 图表区域 -->
    <view class="chart-container">
      <!-- 基础数据趋势图 -->
      <view class="chart-item">
        <text class="chart-title">基础数据趋势</text>
        <view class="chart-wrapper">
          <qiun-data-charts 
            type="line"
            :chartData="baseChartData"
            :width="chartWidth"
            :height="300"
            padding="0"
          ></qiun-data-charts>
        </view>
      </view>
      
      <!-- 产品数据排行图 -->
      <view class="chart-item">
        <text class="chart-title">产品数据排行（TOP10）</text>
        <view class="chart-wrapper">
          <qiun-data-charts 
            type="bar"
            :chartData="productChartData"
            :width="chartWidth"
            :height="400"
            padding="0"
          ></qiun-data-charts>
        </view>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref, computed } from 'vue';
import { onLoad } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const timeRangeList = ref(['今日', '近7天', '近30天', '本月', '上月']);
const selectedTimeRange = ref(1); // 默认近7天
const baseStat = ref({}); // 基础统计数据
const baseChartData = ref({ series: [] }); // 基础数据图表
const productChartData = ref({ series: [] }); // 产品数据图表
const chartWidth = ref(uni.getSystemInfoSync().windowWidth - 40); // 图表宽度

// 页面加载时获取数据
onLoad(() => {
  if (!userStore.token || userStore.userInfo.role !== 'ADMIN') {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getStatData();
});

// 获取统计数据
const getStatData = async () => {
  const timeType = ['today', '7days', '30days', 'month', 'lastMonth'][selectedTimeRange.value];
  
  uni.showLoading({ title: '加载中' });
  try {
    // 获取基础统计数据
    const baseRes = await request({
      url: '/api/admin/stat/base',
      method: 'GET',
      params: { timeType }
    });
    
    // 获取产品统计数据
    const productRes = await request({
      url: '/api/admin/stat/product',
      method: 'GET',
      params: { timeType }
    });
    
    if (baseRes.success && productRes.success) {
      // 处理基础统计数据
      baseStat.value = baseRes.data;
      
      // 处理基础数据图表
      baseChartData.value = {
        categories: baseRes.data.dateList || [],
        series: [
          { name: '访问人数', data: baseRes.data.visitCountList || [] },
          { name: '订单数', data: baseRes.data.orderCountList || [] },
          { name: '成交金额(千元)', data: baseRes.data.amountList || [] }
        ]
      };
      
      // 处理产品数据图表
      const productNames = productRes.data.productNameList || [];
      productChartData.value = {
        categories: productNames,
        series: [
          { name: '浏览量', data: productRes.data.viewCountList || [] },
          { name: '加购数', data: productRes.data.cartCountList || [] },
          { name: '下单数', data: productRes.data.orderCountList || [] }
        ]
      };
    }
  } catch (error) {
    uni.showToast({ title: '数据加载失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 切换时间范围
const handleTimeRangeChange = (event) => {
  selectedTimeRange.value = event.detail.value;
  getStatData();
};

// 导出数据
const exportData = async () => {
  const timeType = ['today', '7days', '30days', 'month', 'lastMonth'][selectedTimeRange.value];
  
  uni.showLoading({ title: '导出中' });
  try {
    const res = await request({
      url: '/api/admin/stat/export',
      method: 'GET',
      params: { timeType },
      responseType: 'blob'
    });
    
    // 下载文件
    const blob = new Blob([res.data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `数据统计_${timeRangeList.value[selectedTimeRange.value]}.xlsx`;
    a.click();
    window.URL.revokeObjectURL(url);
    
    uni.showToast({ title: '导出成功' });
  } catch (error) {
    uni.showToast({ title: '导出失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};
</script>

